//! Bit-parity replay of `fixtures/kalman.json` (Phase 3 Task 3) against the
//! real Python `modules/flow_analysis.py` Kalman filter, generated by
//! `tools/port/gen_kalman_fixtures.py` in the cl_revenue_ops-port worktree.
//! Every float assertion below compares `f64::to_bits` — no epsilon: the
//! whole point of this fixture is that the Rust arithmetic reproduces the
//! exact same IEEE-754 double, term for term, as Python.

use revops_analytics::kalman::{
    calculate_confidence, calculate_kalman_volatility, compute_raw_kalman_observation,
    estimate_depletion_hours, DailyBucket, KalmanFlowFilter, KalmanFlowState, KalmanStateDict,
    NetFlowEntry, CONFIDENCE_RECENCY_HALFLIFE_DAYS, DEPLETION_MIN_DRAIN_SATS_PER_DAY,
    KALMAN_BASE_MEASUREMENT_NOISE, KALMAN_BASE_PROCESS_NOISE, KALMAN_CONFIDENCE_SCALING,
    KALMAN_CONVERGENCE_UNCERTAINTY, KALMAN_INITIAL_VARIANCE, KALMAN_MAX_MEASUREMENT_NOISE,
    KALMAN_MAX_PROCESS_NOISE, KALMAN_MAX_VELOCITY, KALMAN_MIN_MEASUREMENT_NOISE,
    KALMAN_MIN_OBSERVATIONS, KALMAN_MIN_PROCESS_NOISE, KALMAN_MIN_UPDATE_INTERVAL_SECS,
    KALMAN_MIN_VELOCITY, KALMAN_VELOCITY_PROCESS_NOISE, KALMAN_VOLATILITY_SCALING, MAX_CONFIDENCE,
    MIN_CONFIDENCE, MIN_FORWARDS_FOR_HIGH_CONFIDENCE,
};
use serde_json::Value;

fn fixture() -> Value {
    let raw = include_str!("../../../fixtures/kalman.json");
    serde_json::from_str(raw).unwrap()
}

/// Decode a `struct.pack('<d', v).hex()` string (little-endian 8-byte f64)
/// back into the exact `f64` bit pattern Python produced.
fn bits_to_f64(s: &str) -> f64 {
    assert_eq!(
        s.len(),
        16,
        "expected a 16-hex-char (8-byte) little-endian pattern, got {s:?}"
    );
    let mut bytes = [0u8; 8];
    for (i, byte) in bytes.iter_mut().enumerate() {
        *byte = u8::from_str_radix(&s[i * 2..i * 2 + 2], 16).expect("valid hex byte");
    }
    f64::from_bits(u64::from_le_bytes(bytes))
}

fn f64_bits(v: &Value) -> f64 {
    bits_to_f64(v.as_str().expect("expected a hex bit-pattern string"))
}

fn assert_bits_eq(actual: f64, expected: f64, label: &str) {
    assert_eq!(
        actual.to_bits(),
        expected.to_bits(),
        "{label}: bit mismatch (actual={actual:?} [{:016x}], expected={expected:?} [{:016x}])",
        actual.to_bits(),
        expected.to_bits(),
    );
}

fn state_from_json(v: &Value) -> KalmanFlowState {
    KalmanFlowState {
        flow_ratio: f64_bits(&v["flow_ratio"]),
        flow_velocity: f64_bits(&v["flow_velocity"]),
        variance_ratio: f64_bits(&v["variance_ratio"]),
        variance_velocity: f64_bits(&v["variance_velocity"]),
        covariance: f64_bits(&v["covariance"]),
        last_update: v["last_update"].as_i64().unwrap(),
        innovation_variance: f64_bits(&v["innovation_variance"]),
        last_innovation: f64_bits(&v["last_innovation"]),
        observation_count: v["observation_count"].as_i64().unwrap(),
    }
}

fn assert_state_eq(actual: &KalmanFlowState, expected_json: &Value, label: &str) {
    assert_bits_eq(
        actual.flow_ratio,
        f64_bits(&expected_json["flow_ratio"]),
        &format!("{label}.flow_ratio"),
    );
    assert_bits_eq(
        actual.flow_velocity,
        f64_bits(&expected_json["flow_velocity"]),
        &format!("{label}.flow_velocity"),
    );
    assert_bits_eq(
        actual.variance_ratio,
        f64_bits(&expected_json["variance_ratio"]),
        &format!("{label}.variance_ratio"),
    );
    assert_bits_eq(
        actual.variance_velocity,
        f64_bits(&expected_json["variance_velocity"]),
        &format!("{label}.variance_velocity"),
    );
    assert_bits_eq(
        actual.covariance,
        f64_bits(&expected_json["covariance"]),
        &format!("{label}.covariance"),
    );
    assert_eq!(
        actual.last_update,
        expected_json["last_update"].as_i64().unwrap(),
        "{label}.last_update"
    );
    assert_bits_eq(
        actual.innovation_variance,
        f64_bits(&expected_json["innovation_variance"]),
        &format!("{label}.innovation_variance"),
    );
    assert_bits_eq(
        actual.last_innovation,
        f64_bits(&expected_json["last_innovation"]),
        &format!("{label}.last_innovation"),
    );
    assert_eq!(
        actual.observation_count,
        expected_json["observation_count"].as_i64().unwrap(),
        "{label}.observation_count"
    );
}

