// =============================================================================
// estimate_depletion_hours
// =============================================================================

#[test]
fn depletion_cases_match_python() {
    let data = fixture();
    for case in data["depletion_cases"].as_array().unwrap() {
        let id = case["id"].as_str().unwrap();
        let local_sats = f64_bits(&case["local_sats"]);
        let capacity_sats = f64_bits(&case["capacity_sats"]);
        let kalman_ratio = f64_bits(&case["kalman_ratio"]);
        let kalman_velocity = f64_bits(&case["kalman_velocity"]);
        let actual =
            estimate_depletion_hours(local_sats, capacity_sats, kalman_ratio, kalman_velocity);
        match (&actual, case["hours"].as_str()) {
            (None, None) => {}
            (Some(a), Some(expected_hex)) => {
                assert_bits_eq(*a, bits_to_f64(expected_hex), id);
            }
            _ => panic!(
                "{id}: Some/None mismatch (actual={actual:?}, expected={:?})",
                case["hours"]
            ),
        }
    }
}
